import express from "express";
import cors from "cors";
import authRoutes from "./routes/auth.routes.js";
import cookieParser from "cookie-parser";
import questionRoutes from "./routes/question.route.js";
import categoryRoutes from "./routes/category.route.js";
import imagesRoute from "./routes/images.routes.js";
import instructorDocRoutes from "./routes/instructorDoc.routes.js";
import adminVerificationRoutes from "./routes/adminVerification.route.js";
import instructorVerificationRoutes from "./routes/instructorVerification.route.js";
import adminUsersRoute from "./routes/admin.users.route.js";
import courseRoutes from "./routes/course.route.js";
import instructorCoursesRoutes from "./routes/instructor.courses.route.js";
import adminCoursesRoutes from "./routes/admin.courses.route.js";
import adminReportsRoutes from "./routes/admin.reports.route.js";
import userProfileRoutes from "./routes/user.profile.route.js";
import mentorDiscoveryRoutes from "./routes/mentor.discovery.route.js";
import khaltiPaymentRoutes from "./routes/payment.khalti.route.js";
import notificationRoutes from "./routes/notification.route.js";
import walletRoutes from "./routes/wallet.route.js";
import contactSubmissionRoutes from "./routes/contactSubmission.route.js";
const app = express();
app.use(cors({
    origin: "http://localhost:5173",
    credentials: true,
}));
app.use(express.json());
app.use(cookieParser());
app.use("/api/auth", authRoutes);
app.use("/api/questions", questionRoutes);
app.use("/api/categories", categoryRoutes);
app.use("/api", imagesRoute);
app.use("/api", instructorDocRoutes);
app.use("/api", adminVerificationRoutes);
app.use("/api", instructorVerificationRoutes);
app.use("/api/admin", adminUsersRoute);
app.use("/api/admin", adminReportsRoutes);
app.use("/api/courses", courseRoutes);
app.use("/api/instructor/courses", instructorCoursesRoutes);
app.use("/api/admin/courses", adminCoursesRoutes);
app.use("/api/user", userProfileRoutes);
app.use("/api/mentors", mentorDiscoveryRoutes);
app.use("/api/payment", khaltiPaymentRoutes);
app.use("/api/notifications", notificationRoutes);
app.use("/api/wallet", walletRoutes);
app.use("/api", contactSubmissionRoutes);
export default app;
